var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"스승님, 괜찮으십니까?","JPN":"師匠、大丈夫ですか？","ENG":"Are you okay, Master?","TWN":"師父，你沒事吧？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"크게 다치진 않았다. 그보다 저건…….","JPN":"大した怪我ではない。それよりあれは……","ENG":"It's only a scratch. But is that what I think it is…?","TWN":"小事，那是……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저건…… 주시윤 군과 닮아 보이는군요.","JPN":"あれは……アキヤマ君に似ていますね。","ENG":"That… looks a lot like Shiyoon.","TWN":"那是……他長得和周時雲好像。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"저 녀석들, 이런 곳에서 시간을 끌면서 뭘 꾸미나 했더니……","JPN":"あいつら、こんな所で時間を稼いで何を企んでいるかと思えば……","ENG":"So, this is why they've been buying all this time…","TWN":"那些傢伙！我還想他們在這種地方拖延時間是想做什麼……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"용인을 만들고 있었나?","JPN":"龍人を作っていたのか？","ENG":"They were creating a Dragonoid?","TWN":"原來是在製作龍人嗎？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"잘 알고 있군요.","JPN":"よくご存知で。","ENG":"Ah, so you know of this.","TWN":"看來你也知道。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"세상에는 가끔 희석된, 극히 소량의 용의 피를 타고나는 자들이 있지요.","JPN":"世の中には稀に、希釈されたごく少量の龍の血を受け継いだ者がいます。","ENG":"A rare few are born with an infinitesimal amount of diluted Dragon Blood.","TWN":"世界上有一種人，他們的身上流著極少量稀釋過的龍血，"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"우리는 그런 자들을 용인이라 부릅니다.","JPN":"我々はそのような者を龍人と呼びます。","ENG":"We call them Dragonoids.","TWN":"我們稱那種人為龍人。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"확실히 구 관리국에도 환상종들의 혈통으로 이루어진 부대가 있었죠.","JPN":"確か旧管理局にも幻想種の血統で組まれた部隊がありましたね。","ENG":"The Old Administration also had a unit with agents with Bygone bloodlines.","TWN":"舊管理局裡確實也有以夢幻血統打造而成的部隊。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"물론 하나같이 강력한 이들이긴 했지만…….","JPN":"確かにみんな強力な存在でしたが……","ENG":"They were all pretty powerful, for sure…","TWN":"當然其中每一個都很強……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지금의 당신이나 저희들에 비하면 크게 특별할 것 없을 텐데요?","JPN":"今のあなたや僕たちに比べれば、さほど特別な存在でもないと思いますが。","ENG":"But I don't think they were all that formidable compared to you or us, were they?","TWN":"但和現在的我們和你應該沒有差太多吧？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"후후, 알면서도 모른 척 하는 건가요?","JPN":"ふふっ、まだ白を切るおつもりですか？","ENG":"Haha, must you insist on feigning such ignorance?","TWN":"呵呵～你是故意裝傻嗎？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이건 그런 흔해빠진 하급 혼혈들과는 다릅니다.","JPN":"これはそんなありふれた下級混血とは違います。","ENG":"This creature is nothing like those vulgar half-breeds.","TWN":"他和那些混種的可是天差地別。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이 용인은 최초의 용혈을 마셨다고 알려진 인간.","JPN":"この龍人は原初の龍血を飲んだとされる人間。","ENG":"This Dragonoid was forged from the very first man to drink Dragon Blood.","TWN":"這個龍人喝下的是最原始的龍血。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 구도자의 업을 계승하는 자에게서 추출한 용혈로 제련해낸 것이니까요.","JPN":"その求道者のカルマを受け継ぐ者から抽出した龍血で製錬したものですからね。","ENG":"The Dragon Blood we extracted from he who inherited the Seeker's karma.","TWN":"是使用從求道者業障繼承者的身上抽取出來的龍血去煉製的。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"호오, 잘 감췄다고 생각했는데 벌써 거기까지 알아내셨군요.","JPN":"ほう、うまく隠したと思っていましたが、もうそこまで調べたのですね。","ENG":"Oh, I thought I had hidden that fact quite well from you, but you managed to figure it out.","TWN":"哈！我還以為藏得很好呢，沒想到你竟然知道這麼多！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"운이 좋았죠. 마침 저희 중에도 용의 피에 조예가 깊은 분이 계셨으니까요.","JPN":"運が良かったです。私たちの中にも龍の血に造詣が深い方がいましたから。","ENG":"We were lucky. It just so happened that someone with immense knowledge about Dragon Blood was with us.","TWN":"我們運氣好，有位研究龍血相當透徹的人在我們當中。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신이 제공한 그 소년의 용혈 샘플을 보고 바로 알 수 있었습니다.","JPN":"あなたが提供したその少年の龍血サンプルを見てすぐにわかりました。","ENG":"We could tell with one look at the lad's Dragon Blood sample you provided.","TWN":"當你將那個少年的血拿給我們時，他一看就立刻知道！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 소년이야말로, <color=#ffd34c>구도자</color>의 직계 후손이라는 것을.","JPN":"その少年こそ、<color=#ffd34c>求道者</color>の直系子孫であるということを。","ENG":"He is the direct descendent of <color=#ffd34c>the Seeker of Truth</color>.","TWN":"那個少年就是<color=#ffd34c>求道者</color>的直系後裔。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"알다시피, 구도자는 용혈을 마시고도 번뇌에 빠져 진정한 용이 되지 못했습니다.","JPN":"ご存知のように、求道者は龍血を飲んだ後も煩悩に苛まれ、真の龍にはなれませんでした。","ENG":"As you are well aware, the Seeker never became a true Dragon, even after partaking in the Dragon Blood, as he failed to overcome his Kleshas.","TWN":"你也知道，求道者就算喝下龍血也會陷入煩惱當中，而無法成為真正的龍。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……참으로 한심한 일이죠.","JPN":"……実に情けないことです。","ENG":"…A most pathetic turn of events, I must say.","TWN":"……現實是殘酷的。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 이 용인은 소년으로부터 뽑아낸 순수한 용혈만으로 이루어진 존재.","JPN":"しかし、この龍人は少年から抽出した純粋な龍血だけで構成された存在。","ENG":"But this Dragonoid has been constructed from the purest Dragon Blood extracted from the lad.","TWN":"不過這個龍人完全是用少年身上的血打造而成的，"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아직은 인간의 모습이 남아 있지만, 곧 껍질을 깨고 진정한 <color=#ffd34c>최초의 용</color>으로 다시 태어날 겁니다.","JPN":"まだ人間の姿が残っていますが、まもなく殻を割り真なる<color=#ffd34c>原初の龍</color>として生まれ変わるでしょう。","ENG":"Although he yet remains human in form, he shall soon break through his shell and be born again as <color=#ffd34c>the First Dragon</color>.","TWN":"雖然還留有人類的外貌，但他很快就會脫離那副軀殼，重生為<color=#ffd34c>真正的龍</color>！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이 거짓된 세상과, 당신들 같은 위선자들을 징벌하기 위해서!","JPN":"この偽りの世界と、あなたたちのような偽善者に罰を与えるために！","ENG":"He shall bring judgment upon this false world and upon hypocrites like you!","TWN":"為的是要懲罰這個虛謊的世界，和你們這些偽善的人！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"용 사냥꾼으로 불리던 당신이라면 느꼈겠죠?","JPN":"龍の狩人と呼ばれたあなたなら感じたでしょう？","ENG":"As someone who was once dubbed a dragon hunter, you can feel it, can't you?","TWN":"曾經被稱為是龍獵手的你應該有感受到吧？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이 용인이 얼마나 강력한 존재인지 말입니다.","JPN":"この龍人がどれほど強力な存在かを。","ENG":"You can feel what a potent being this Dragonoid is.","TWN":"這個龍人有多強！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"흐음, 그래서 굳이 합의를 파기하면서까지 주시윤 군을 납치했군요.","JPN":"ふむ、それでわざわざ合意を破棄してまでアキヤマ君を攫ったんですね。","ENG":"Hmm… So that's why you went to the lengths of breaching our agreement to abduct Joo Shiyoon.","TWN":"嗯嗯，所以你們才不惜破壞協議也要綁架周時雲嗎？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 그래 봐야 아직은 미완성품 아닌가요?","JPN":"とはいえ、まだ未完成品なのではありませんか？","ENG":"Try as you might, this thing is still incomplete, isn't it?","TWN":"但我看他應該還只是個半成品吧？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이렇게 모습을 드러낸 이상, 지금 여기서 파괴해 버리면 어쩔 생각이시죠?","JPN":"ここに姿を現した以上、今ここで僕たちが破壊してしまったらどうするつもりですか？","ENG":"Now that we know what you're up to, what if we just destroy it here on the spot?","TWN":"你就這樣把他放出來，如果我們現在就立刻毀掉他，那你打算怎麼辦呢？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그렇다면 당신들이 구하러 온 소년을 영원히 만날 수 없게 되겠죠.","JPN":"そうしたら、あなたたちが助けに来た少年には永遠に会えなくなるでしょう。","ENG":"Then you shall never see the one you've come to save again.","TWN":"這樣的話，你們就再也見不到那個少年囉～"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"용혈이 완전히 분리되기 전에 용인이 파괴되면, 그 소년도 죽게 될 테니까요.","JPN":"龍血が完全に分離する前に龍人が破壊されたら、あの少年も死んでしまいますからね。","ENG":"If the Dragonoid is destroyed before the Dragon Blood is completely removed, the boy shall perish.","TWN":"在龍血完全分離前，萬一龍人被毀掉，那個少年也沒得活。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 이것 참.","JPN":"ハハ、まいりましたね。","ENG":"Haha, oh my.","TWN":"哈哈哈，真是的！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"성녀님께서 잘 모르시는 모양인데 우리 스승님은 대의를 따르는 분입니다.","JPN":"聖女様はご存知ないようですが、我が師匠は大義に従う方です。","ENG":"You might not know this, but my Master here is all about the greater good.","TWN":"我說聖女大人，你似乎不太明白我們師父的為人，他完全沒在管什麼兒女私情的。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"해야 할 일을 위해서라면 제자 한둘 따위 서슴없이 버릴 수 있죠.","JPN":"なすべきことのためなら弟子の一人や二人ぐらい躊躇なく見捨てるでしょう。","ENG":"She'll abandon a couple of her apprentices in a heartbeat if that's what it takes to do what she must.","TWN":"為了顧全大局，拋棄一兩個徒弟算什麼！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"직접 버림받아 본 입장에서 하는 말이니 틀림없습니다.","JPN":"実際に見捨てられた立場なので、間違いないです。","ENG":"I can assure you that's true, having been abandoned myself.","TWN":"這可是我的親身經歷，可信度百分百！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇죠, 스승님?","JPN":"そうですよね、師匠？","ENG":"Isn't that right, Master?","TWN":"師父我沒說錯吧？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"그 아이도…… 저와 같은 운명을 걷게 될까요?","JPN":"あの子も……私と同じ運命を歩むことになるのでしょうか。","ENG":"Will the child… be destined to the same fate as mine?","TWN":"那個孩子……也會和我走上相同的命運嗎？"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"모른다. 내게 미래를 보는 능력 같은 건 없어.","JPN":"わからない。私に未来を見る能力なんてない。","ENG":"I don't know. I can't see the future.","TWN":"不知道，我沒有預知未來的能力。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그리고 애초에 난 운명이니 숙명이니 하는 말을 싫어해.","JPN":"それに、そもそも私は運命や宿命なんていう言葉が嫌いだ。","ENG":"Besides, I never liked words like destiny or fate.","TWN":"更何況我根本不相信命運這種東西。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 꼬마의 미래는, 그 녀석 자신이 결정하겠지.","JPN":"あの子の未来は、あいつ自身が決めるだろう。","ENG":"I'm sure the kid will decide his own future for himself.","TWN":"那小鬼的未來由他自己決定。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"후훗……. 스승님다운 말씀이네요.","JPN":"フフッ……師匠らしいお言葉ですね。","ENG":"Haha… Of course you'd say that, Master.","TWN":"呵呵……果然是師父會說的話。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"보통은 이런 질문을 들으면 다 잘 될 거라고 말해 줄 텐데 말이죠.","JPN":"普通ならこんな質問を受けたら、すべてうまくいくと言ってくれますよ。","ENG":"Most folks would say everything will be all right.","TWN":"一般人聽到這種話，應該都會回些安慰的話吧。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"약속해 주세요, 스승님. 그 아이를 보살펴 주겠다고.","JPN":"約束してください、師匠。あの子の面倒を見てくれると。","ENG":"Promise me, Master. Promise me that you'll take care of him.","TWN":"師父，答應我你會好好照顧他，"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MOTHER_NPC_YOON_NULL","text":{"KOREA":"그 아이가 저처럼 되지 않게……. 진실에서 멀어지게 해 주겠다고요.","JPN":"あの子が私みたいにならないように……真実から遠ざけてあげてください。","ENG":"Don't let him become like me… Please keep him as far away from the truth as possible.","TWN":"不要讓他變得像我一樣……永遠不要讓他知道真相。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……그래, 그 정도라면.","JPN":"……わかった、それぐらいなら。","ENG":"…I will, if that's all you ask.","TWN":"……好，如果是這樣…"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"약속하지.","JPN":"約束する。","ENG":"I promise.","TWN":"我答應你。"},"stage":{"bg":"MAINSTREAM_7110010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……스승님?","JPN":"……師匠？","ENG":"…Master?","TWN":"……師父？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"용인이 자율활동을 개시한 걸 보니 이미 용혈을 상당량 추출했나 보군.","JPN":"龍人が自律活動を開始したということは、すでに相当量の龍血を抽出したようだな。","ENG":"If the Dragonoid's out and about, they must have already extracted a considerable amount of Dragon Blood.","TWN":"龍人可以開始自行活動的話，就表示已經抽出大量的龍血，"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"서두르지 않으면 망할 제자 놈의 목숨이 위험하겠어.","JPN":"急がないと、うちの手を焼く弟子の命が危ない。","ENG":"If we don't hurry, my blasted apprentice's life could be in peril.","TWN":"不快點的話，那個笨徒弟的性命會有危險。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"미완성의 용인은 손상을 입으면 제자 녀석이 있는 곳으로 퇴각할 거다.","JPN":"未完成の龍人は損傷を受けると弟子のいる場所に退却するだろう。","ENG":"The incomplete Dragonoid will retreat to where Shiyoon is when it sustains enough damage.","TWN":"半完成的龍人如果受損，應該就會撤退到笨徒弟所在的地方，"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"손상을 회복하기 위해선 아직 본체의 용혈이 필요할 테니까.","JPN":"損傷を回復するためには、まだ本体の龍血が必要だからな。","ENG":"It'll still need the Dragon Blood from the main body to repair its wounds.","TWN":"因為他需要本體的龍血來恢復受損的部分。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그러니 용인이 퇴각할 정도만 피해를 입힌 뒤 추적한다.","JPN":"だから龍人が退却する程度のダメージを与えた後、追跡する。","ENG":"So we'll damage the Dragonoid just enough until it retreats, then follow its tracks.","TWN":"所以我們就讓龍人稍微受損後再跟蹤他。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"실수로라도 용인을 죽이지 않게 조심하도록, 나유빈.","JPN":"ミスでもして龍人を殺さないように気をつけろ、イチノセ。","ENG":"Try not to kill the Dragonoid by mistake, Na Yubin.","TWN":"羅瑜斌，你小心不要失手殺掉龍人。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"알겠습니다, 스승님.","JPN":"承知しました、師匠。","ENG":"Got it, Master.","TWN":"是，師父。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};